noncompliant:
for (int i = 0; i < 10; i++) { // Noncompliant: loop only executes once
    printf("i is %d", i);
    break;
}

while (condition) { // Noncompliant: loop designed to run only once
    doSomething();
    return; // Always exits on first iteration
}

do {
    processData();
    break; // Noncompliant: break ensures only one iteration
} while (true);

compliant:
if (0 < 10) { // Compliant: using if instead of loop
    printf("i is %d", 0);
}

if (condition) { // Compliant: conditional execution
    doSomething();
    return;
}

// Compliant: proper loop or conditional
if (needsProcessing) {
    processData();
}
